+    })[circuitBreakerState] || new Map();
+
+  function enterCircuit(
+    origin: string,
+    config: Required<CircuitBreakerOptions>
+  ): CircuitRequest {
+    const now = Date.now();
+    let state = circuits.get(origin);
+    if (!state) {
+      state = { failures: 0, state: "closed", openedAt: 0, probes: 0 };
+      circuits.set(origin, state);
+    }
+    if (state.state === "open") {
+      if (now - state.openedAt < config.cooldown) {
+        throw new Error("Circuit breaker is open");
+      }
+      state.state = "half-open";
+    }
+    const probe = state.state === "half-open";
+    if (probe) {
+      if (state.probes >= config.halfOpenMaxRequests) {
+        throw new Error("Circuit breaker is open");
+      }
+      state.probes++;
+    }
+    return { origin, config, probe };
+  }
+
+  function leaveCircuit(
+    request: CircuitRequest,
+    outcome: "success" | "failure" | "neutral"
+  ) {
+    const state = circuits.get(request.origin);
+    if (!state) {
+      return;
+    }
+    if (request.probe) {
+      state.probes--;
+      if (outcome === "failure") {
+        state.state = "open";
+        state.openedAt = Date.now();
+      } else if (outcome === "success") {
+        state.state = "closed";
+        state.failures = 0;
+      }
+      return;
+    }
+    if (outcome === "success") {
+      state.failures = 0;
+    } else if (outcome === "failure") {
+      state.failures++;
+      if (state.failures >= request.config.threshold) {
+        state.state = "open";
+        state.openedAt = Date.now();
+      }
+    }
+  }
