+import { describe, expect, it, vi } from "vitest";
+import { createFetch } from "../src/fetch.ts";
+
+const circuit = {
+  threshold: 2,
+  cooldown: 100,
+  failureStatusCodes: [500],
+};
+
+describe("circuit breaker", () => {
+  it("opens after consecutive configured status failures, including ignored errors", async () => {
+    const fetch = vi.fn(async () => new Response("failure", { status: 500 }));
+    const $fetch = createFetch({ fetch: fetch as typeof globalThis.fetch });
+
+    await $fetch("https://one.example/a", {
+      circuitBreaker: circuit,
+      ignoreResponseError: true,
+      retry: false,
+    });
+    await $fetch("https://one.example/b", {
+      circuitBreaker: circuit,
+      ignoreResponseError: true,
+      retry: false,
+    });
+    await expect(
+      $fetch("https://one.example/c", { circuitBreaker: circuit })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledTimes(2);
+  });
+
+  it("uses the effective URL after baseURL and onRequest rewriting", async () => {
+    const fetch = vi.fn(async () => new Response("failure", { status: 500 }));
+    const $fetch = createFetch({ fetch: fetch as typeof globalThis.fetch });
+    const options = {
+      circuitBreaker: { ...circuit, threshold: 1 },
+      retry: false,
+      onRequest: ({ request }: any) => {
+        request.request = "https://rewritten.example/path";
+      },
+    };
+
+    await expect($fetch("/path", { ...options, baseURL: "https://base.example" })).rejects.toThrow();
+    await expect(
+      $fetch("https://rewritten.example/other", { circuitBreaker: options.circuitBreaker })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledOnce();
+  });
+
+  it("shares origin state with derived clients", async () => {
+    const fetch = vi.fn(async () => new Response("failure", { status: 500 }));
+    const parent = createFetch({ fetch: fetch as typeof globalThis.fetch });
+    const child = parent.create({});
+
+    await expect(
+      parent("https://shared.example", {
+        circuitBreaker: { ...circuit, threshold: 1 },
+        retry: false,
+      })
+    ).rejects.toThrow();
+    await expect(
+      child("https://shared.example", { circuitBreaker: circuit })
+    ).rejects.toThrow("Circuit breaker is open");
+    expect(fetch).toHaveBeenCalledOnce();
+  });
+
+  it("holds a half-open probe slot through completion and closes on success", async () => {
+    vi.useFakeTimers();
+    try {
+      let resolveProbe!: (response: Response) => void;
+      const fetch = vi
+        .fn()
+        .mockResolvedValueOnce(new Response("failure", { status: 500 }))
+        .mockImplementationOnce(
+          () => new Promise<Response>((resolve) => (resolveProbe = resolve))
+        );
+      const $fetch = createFetch({ fetch: fetch as typeof globalThis.fetch });
+      const options = {
+        circuitBreaker: { ...circuit, threshold: 1 },
+        retry: false,
+      };
+
+      await expect($fetch("https://recover.example", options)).rejects.toThrow();
+      await vi.advanceTimersByTimeAsync(100);
+      const probe = $fetch("https://recover.example", options);
+      await expect($fetch("https://recover.example", options)).rejects.toThrow(
+        "Circuit breaker is open"
+      );
+      resolveProbe(new Response("ok"));
+      await expect(probe).resolves.toBe("ok");
+      await expect($fetch("https://recover.example", options)).resolves.toBe("failure");
+    } finally {
+      vi.useRealTimers();
+    }
+  });
+
+  it("accounts for one exhausted retry sequence as one failure", async () => {
